// CURSOR
const cur = document.getElementById('cursor');
const curR = document.getElementById('cursorRing');
let mx=0,my=0;
document.addEventListener('mousemove', e => { mx=e.clientX; my=e.clientY; cur.style.left=mx+'px'; cur.style.top=my+'px'; });
function animRing(){
  const rx=parseFloat(curR.style.left||0), ry=parseFloat(curR.style.top||0);
  curR.style.left=(rx+(mx-rx)*0.12)+'px'; curR.style.top=(ry+(my-ry)*0.12)+'px';
  requestAnimationFrame(animRing);
}
animRing();
document.querySelectorAll('button,a,.pc,.sz,.f-soc,.f-col a,.nav-links a').forEach(el=>{
  el.addEventListener('mouseenter',()=>{ cur.style.transform='translate(-50%,-50%) scale(2.5)'; curR.style.transform='translate(-50%,-50%) scale(1.6)'; });
  el.addEventListener('mouseleave',()=>{ cur.style.transform='translate(-50%,-50%) scale(1)'; curR.style.transform='translate(-50%,-50%) scale(1)'; });
});

// GOLD DUST
const dustEl = document.getElementById('dust');
['#d4a017','#f0c040','#c0272d','#ffffff'].forEach((col,ci)=>{
  for(let i=0;i<12;i++){
    const p=document.createElement('div'); p.className='dust-p';
    const s=Math.random()*4+1;
    p.style.cssText=`left:${Math.random()*100}%;width:${s}px;height:${s}px;background:${col};animation-duration:${Math.random()*10+8}s;animation-delay:${Math.random()*10}s;border-radius:${Math.random()>0.5?'50%':'2px'};`;
    dustEl.appendChild(p);
  }
});

// LOGIN
const CODE=['B','S','D','L'];
const inputs=[1,2,3,4].map(i=>document.getElementById('c'+i));
inputs[0].focus();
inputs.forEach((inp,i)=>{
  inp.addEventListener('input',e=>{
    inp.value=e.target.value.toUpperCase();
    inp.classList.toggle('filled',inp.value.length>0);
    if(inp.value&&i<3) inputs[i+1].focus();
  });
  inp.addEventListener('keydown',e=>{
    if(e.key==='Backspace'&&!inp.value&&i>0){ inputs[i-1].focus(); inputs[i-1].value=''; inputs[i-1].classList.remove('filled'); }
    if(e.key==='Enter') tryLogin();
  });
});
document.getElementById('login-btn').addEventListener('click',tryLogin);
function tryLogin(){
  const vals=inputs.map(i=>i.value.toUpperCase());
  if(CODE.every((c,i)=>vals[i]===c)){
    document.getElementById('login-page').classList.add('hidden');
    const main=document.getElementById('main-site');
    main.style.display='block';
    setTimeout(()=>main.classList.add('visible'),60);
  } else {
    const err=document.getElementById('login-error'); err.classList.add('show');
    inputs.forEach(inp=>{ inp.style.borderColor='#c0272d'; inp.style.boxShadow='0 0 12px rgba(192,39,45,0.3)'; });
    setTimeout(()=>{
      err.classList.remove('show');
      inputs.forEach(inp=>{ inp.value=''; inp.classList.remove('filled'); inp.style.borderColor=''; inp.style.boxShadow=''; });
      inputs[0].focus();
    },1600);
  }
}

// PRODUCTS
const PRODS = [
  {id:1,name:'CHERUB HOODIE',desc:'Oversized. Baroque angel embroidery on chest. 400gsm cotton fleece.',price:0.00,tag:'NEW',sizes:['S','M','L','XL'],emoji:'🖤',grad:'linear-gradient(135deg,#1a0808,#0c0c0c)'},
  {id:2,name:'GOLD AK TEE',desc:'Acid-washed. Gold foil print. 100% organic heavyweight cotton.',price:0.00,tag:'HOT',sizes:['XS','S','M','L','XL'],emoji:'☠️',grad:'linear-gradient(135deg,#1a1a0a,#080808)'},
  {id:3,name:'BAROQUE CARGO',desc:'Relaxed cargo cut. Red satin liner. Byoki patch pocket.',price:0.00,tag:null,sizes:['S','M','L'],emoji:'🖤',grad:'linear-gradient(135deg,#1a0808,#0d0d0d)'},
  {id:4,name:'DYNASTY JACKET',desc:'Coach silhouette. Gold chain detail. Satin interior.',price:0.00,tag:'LIMITED',tagType:'gold',sizes:['M','L','XL'],emoji:'🌑',grad:'linear-gradient(135deg,#0e0a00,#0d0d0d)'},
  {id:5,name:'ANGEL CAP',desc:'6-panel structured. Byoki kanji embroidered. Gold strapback.',price:0.00,tag:null,sizes:['ONE SIZE'],emoji:'👑',grad:'linear-gradient(135deg,#160808,#111)'},
  {id:6,name:'MONEY CREWNECK',desc:'Glow-in-dark stack print. Heavyweight fleece. Dropped shoulder.',price:0.00,tag:'NEW',sizes:['S','M','L','XL','XXL'],emoji:'⚡',grad:'linear-gradient(135deg,#0e0800,#080808)'},
  {id:7,name:'RED SOUL BUCKET',desc:'Washed canvas. All-over graphic print. Reversible.',price:0.00,tag:null,sizes:['S/M','L/XL'],emoji:'🌀',grad:'linear-gradient(135deg,#1a0505,#0d0d0d)'},
  {id:8,name:'GRAFFITI TOTE',desc:'Natural canvas. Screen-printed. Heavy-duty woven handles.',price:0.00,tag:null,sizes:['ONE SIZE'],emoji:'🛍️',grad:'linear-gradient(135deg,#111,#1a1a1a)'},
];

let selSizes={}, cart=[];

function renderProds(){
  document.getElementById('products-grid').innerHTML = PRODS.map(p=>`
    <div class="pc" id="pc-${p.id}">
      <div class="pc-img">
        <div class="pc-img-inner" style="background:${p.grad}">
          <div class="pc-bg-art"><img src="data:image/png;base64," alt="" id="pc-bg-${p.id}"></div>
          <div class="pc-emoji">${p.emoji}</div>
          <div class="pc-number">BYK-00${p.id}</div>
        </div>
        ${p.tag?`<div class="pc-tag ${p.tagType||''}">${p.tag}</div>`:''}
        <div class="pc-actions">
          <button class="pc-add" onclick="addItem(${p.id})">+ Add to Bag</button>
        </div>
      </div>
      <div class="pc-info">
        <div class="pc-name-bar">
          <div class="pc-name">${p.name}</div>
          <div class="pc-desc">${p.desc}</div>
        </div>
        <div class="pc-footer">
          <div class="pc-price">R${p.price.toLocaleString()}</div>
          <div class="pc-sizes">${p.sizes.slice(0,3).map(s=>`<div class="sz ${selSizes[p.id]===s?'active':''}" onclick="pickSize(${p.id},'${s}',this)">${s[0]}</div>`).join('')}</div>
        </div>
      </div>
    </div>
  `).join('');
  // Set product card background logos
  document.querySelectorAll('[id^="pc-bg-"]').forEach(img => {
    img.src = 'data:image/png;base64,';
  });
}

function pickSize(pid,s,el){
  selSizes[pid]=s;
  el.closest('.pc-sizes').querySelectorAll('.sz').forEach(d=>d.classList.remove('active'));
  el.classList.add('active');
}

function addItem(pid){
  const p=PRODS.find(x=>x.id===pid);
  const sz=selSizes[pid]||p.sizes[0];
  const ex=cart.find(i=>i.id===pid&&i.size===sz);
  if(ex) ex.qty++; else cart.push({...p,size:sz,qty:1});
  updateCart();
  const btn=document.querySelector(`#pc-${pid} .pc-add`);
  const orig=btn.textContent; btn.textContent='✓ Added'; btn.style.background='#d4a017'; btn.style.color='#060606';
  setTimeout(()=>{ btn.textContent=orig; btn.style.background=''; btn.style.color=''; },1200);
}

function updateCart(){
  const n=cart.reduce((s,i)=>s+i.qty,0);
  const c=document.getElementById('cart-count');
  c.textContent=n; c.classList.toggle('show',n>0);
  renderCart();
}

function renderCart(){
  const body=document.getElementById('cart-body');
  const foot=document.getElementById('cart-foot');
  if(!cart.length){
    body.innerHTML=`<div class="cart-empty"><div class="cart-empty-ico">🛒</div><p>Your bag is empty</p></div>`;
    foot.style.display='none'; return;
  }
  foot.style.display='block';
  body.innerHTML=cart.map((it,i)=>`
    <div class="cart-item">
      <div class="ci-thumb">${it.emoji}</div>
      <div class="ci-details">
        <div class="ci-name">${it.name}</div>
        <div class="ci-meta">Size: ${it.size}</div>
        <div class="ci-qty">
          <button class="ci-q-btn" onclick="qtyChange(${i},-1)">−</button>
          <span class="ci-q-num">${it.qty}</span>
          <button class="ci-q-btn" onclick="qtyChange(${i},1)">+</button>
        </div>
      </div>
      <div class="ci-right">
        <div class="ci-price">R${(it.price*it.qty).toLocaleString()}</div>
        <button class="ci-rm" onclick="removeItem(${i})">✕</button>
      </div>
    </div>
  `).join('');
  document.getElementById('cart-total-val').textContent='R'+cart.reduce((s,i)=>s+i.price*i.qty,0).toLocaleString();
}

function qtyChange(i,d){ cart[i].qty+=d; if(cart[i].qty<=0) cart.splice(i,1); updateCart(); }
function removeItem(i){ cart.splice(i,1); updateCart(); }
function openCart(){ document.getElementById('cart-overlay').classList.add('open'); document.getElementById('cart-drawer').classList.add('open'); document.body.style.overflow='hidden'; }
function closeCart(){ document.getElementById('cart-overlay').classList.remove('open'); document.getElementById('cart-drawer').classList.remove('open'); document.body.style.overflow=''; }
function checkout(){ cart=[]; updateCart(); closeCart(); document.getElementById('order-modal').classList.add('open'); }
function closeModal(){ document.getElementById('order-modal').classList.remove('open'); }
function goto(id){ document.getElementById(id)?.scrollIntoView({behavior:'smooth'}); }

renderProds();
